// mm/src/api/uploadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

const ACCESS_KEY = 'mm_accessToken';

function getAccessToken() {
  return localStorage.getItem(ACCESS_KEY) || '';
}

/**
 * uploadDocument.php
 * requires: accessToken, document
 * returns: success message, documentId, filePath
 */
export const uploadDocuments = async (file, onProgress) => {
  // DEV MOCK if no env var set
  if (!process.env.REACT_APP_API_BASE_URL) {
    return new Promise((resolve) => {
      const total = file?.size || 1024 * 300;
      let loaded = 0;
      const interval = setInterval(() => {
        loaded += total / 12;
        const pct = Math.min(100, Math.round((loaded / total) * 100));
        onProgress && onProgress(pct);
        if (pct >= 100) {
          clearInterval(interval);
          resolve({
            data: {
              success: true,
              message: 'Mock uploadDocument success',
              documentId: `mock_${Date.now()}`,
              filePath: `/mock/docs/${encodeURIComponent(file?.name || 'document')}`,
              filename: file?.name || 'document',
            },
          });
        }
      }, 120);
    });
  }

  const accessToken = getAccessToken();
  const url = `${API_BASE}/uploadDocument.php`;

  const form = new FormData();
  // backend expects "document" per your requirement
  form.append('document', file);

  return withAuthRetry(() =>
    axios.post(url, form, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
        'Content-Type': 'multipart/form-data',
      },
      onUploadProgress: (evt) => {
        if (onProgress && evt.total) {
          const pct = Math.round((evt.loaded * 100) / evt.total);
          onProgress(pct);
        }
      },
    })
  );
};
